import { createRemoteJWKSet } from 'jose';

const TEN_MIN = 10 * 60 * 1000;

type JwksFn = ReturnType<typeof createRemoteJWKSet>;
interface Entry {
  jwks: JwksFn;
  fetchedAt: number;
}

const cache = new Map<string, Entry>();

/**
 * Returns a cached JWKS resolver for a given JWKS URI. The underlying
 * createRemoteJWKSet from jose maintains its own HTTP cache (cacheMaxAge),
 * and this module additionally memoizes the resolver instance per URI so
 * repeated verifications reuse the same state.
 */
export function getJwks(jwksUri: string): JwksFn {
  const now = Date.now();
  const e = cache.get(jwksUri);
  if (e && now - e.fetchedAt < TEN_MIN) return e.jwks;
  const jwks = createRemoteJWKSet(new URL(jwksUri), { cacheMaxAge: TEN_MIN });
  cache.set(jwksUri, { jwks, fetchedAt: now });
  return jwks;
}

/** For tests — clears the cache. */
export function __resetJwksCacheForTest(): void {
  cache.clear();
}

/** For tests — overrides the cache entry with a supplied resolver. */
export function __setJwksForTest(jwksUri: string, jwks: unknown): void {
  cache.set(jwksUri, { jwks: jwks as JwksFn, fetchedAt: Date.now() });
}
