import { jwtVerify } from 'jose';
import { getJwks } from './jwks-cache';
import type { SessionUser } from '../types';

export interface VerifierOptions {
  /** Broker origin, e.g., https://kannegiesser.ai */
  brokerOrigin: string;
  /** Require access[appSlug] to be non-empty. */
  appSlug: string;
}

const ISS = 'https://kannegiesser.ai/auth';

/**
 * Factory for a JWT verifier bound to a broker origin + app slug.
 * Returns a function that takes a raw compact JWT and resolves to a
 * SessionUser if the token is valid, issued by the expected broker,
 * and grants any role on this appSlug; otherwise null.
 */
export function createKaiVerifier(opts: VerifierOptions) {
  const jwksUri = `${opts.brokerOrigin}/auth/.well-known/jwks.json`;
  return async function verify(
    jwt: string | undefined | null,
  ): Promise<SessionUser | null> {
    if (!jwt) return null;
    try {
      const { payload } = await jwtVerify(jwt, getJwks(jwksUri), { issuer: ISS });
      const p = payload as unknown as {
        sub: string;
        email: string;
        name: string;
        access: Record<string, string[]>;
        groups: string[];
        exp: number;
      };
      const roles = p.access?.[opts.appSlug];
      if (!roles || roles.length === 0) return null;
      return {
        sub: p.sub,
        email: p.email,
        name: p.name,
        access: p.access,
        groups: p.groups,
        expiresAt: p.exp,
      };
    } catch {
      return null;
    }
  };
}
